// Two-sum in a SORTED array — O(n) instead of O(n²)
function twoSum(arr, target) {
  let l = 0, r = arr.length - 1;
  while (l < r) {
    const s = arr[l] + arr[r];
    if (s === target) return [l, r];
    if (s < target) l++;
    else r--;
  }
  return null;
}

console.log(twoSum([1, 2, 4, 6, 8, 11], 10)); // [1, 4]
